`,xt(t.p,{children:xt(t.img,{src:"./pic/dataset-compare-table.jpg",alt:""})}),`
`,xt(t.p,{children:[xt(t.strong,{children:"Dataset comparison."})," We focus on outfit-level VTON. Our data is built upon real high-solution real-world garment and model images."]})]})}function RQ(e={}){const{wrapper:t}=e.components||{};return t?xt(t,{...e,children:xt(Qb,{...e})}):Qb(e)}function e0(e){const t={h1:"h1",img:"img",p:"p",strong:"strong",...e.components};return xt(Le,{children:[xt(t.h1,{children:"Dataset construction"}),`
